from collections import Counter

class Solution(object):
    def minGroupsForValidAssignment(self, balls):
        freq = Counter(Counter(balls).values())  # freq of each ball-value's count
        counts = list(freq.keys())               # distinct frequency values
        min_freq = min(counts)

        def groups_for_x(x):
            # Try group sizes x and x+1
            total = 0
            for f, cnt in freq.items():
                # Distribute f occurrences of this value into groups of size x or x+1
                a = f // (x + 1)
                b = f % (x + 1)
                if b == 0:
                    total += a * cnt
                elif x - b <= a:
                    total += (a + 1) * cnt
                else:
                    return float('inf')  # impossible for this x
            return total

        ans = float('inf')
        for x in range(1, min_freq + 1):
            ans = min(ans, groups_for_x(x))
        return ans
